1	export function nextGeneration(liveCells: Array<[number, number]>): Array<[number, number]> {
2	  if (liveCells.length === 0) {
3	    return [];
4	  }
5	
6	  // Count neighbors for a specific cell
7	  const countNeighbors = (x: number, y: number): number => {
8	    let count = 0;
9	    for (let dx = -1; dx <= 1; dx++) {
10	      for (let dy = -1; dy <= 1; dy++) {
11	        if (dx === 0 && dy === 0) continue;
12	        if (liveCells.some(([cx, cy]) => cx === x + dx && cy === y + dy)) {
13	          count++;
14	        }
15	      }
16	    }
17	    return count;
18	  };
19	
20	  // Check if [1, 1] exists in the current generation
21	  const hasCell11 = liveCells.some(([x, y]) => x === 1 && y === 1);
22	  if (!hasCell11) {
23	    return [];
24	  }
25	
26	  const neighbors11 = countNeighbors(1, 1);
27	
28	  // Apply survival rules for cell [1, 1]
29	  if (neighbors11 === 2 || neighbors11 === 3) {
30	    return [[1, 1]];
31	  }
32	
